using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContext.Create();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Student CreateStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
    {
        var student = new Student
        {
            LastName = lastName,
            FirstMidName = firstName,
            EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
        };
        _context.Students.Add(student);
        _context.SaveChanges();
        return student;
    }

    #region Index

    [Fact]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        CreateStudent("Zimmerman", "Alice");
        CreateStudent("Adams", "Bob");
        CreateStudent("Miller", "Carol");

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count);
        Assert.Equal("Adams", model[0].LastName);
        Assert.Equal("Miller", model[1].LastName);
        Assert.Equal("Zimmerman", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsStudentsDescending()
    {
        CreateStudent("Adams", "Alice");
        CreateStudent("Zimmerman", "Bob");

        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("Zimmerman", model[0].LastName);
        Assert.Equal("Adams", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_ReturnsStudentsOrderedByEnrollmentDate()
    {
        CreateStudent("B", "B", new DateTime(2024, 1, 1));
        CreateStudent("A", "A", new DateTime(2022, 1, 1));

        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("A", model[0].LastName);
        Assert.Equal("B", model[1].LastName);
    }

    [Fact]
    public void Index_DateDescSort_ReturnsStudentsOrderedByEnrollmentDateDescending()
    {
        CreateStudent("A", "A", new DateTime(2022, 1, 1));
        CreateStudent("B", "B", new DateTime(2024, 1, 1));

        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("B", model[0].LastName);
        Assert.Equal("A", model[1].LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        CreateStudent("Smith", "John");
        CreateStudent("Johnson", "Jane");

        var result = _controller.Index(null, null, "Smith", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Single(model);
        Assert.Equal("Smith", model[0].LastName);
