using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestDbContext.Create();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);

        // Seed a department for FK
        _context.Departments.Add(new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000, StartDate = DateTime.Now });
        _context.SaveChanges();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Course CreateCourse(int id = 1001, string title = "Intro to CS", int credits = 3)
    {
        var course = new Course { CourseID = id, Title = title, Credits = credits, DepartmentID = 1 };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        CreateCourse(1001, "Course A");
        CreateCourse(1002, "Course B");

        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var course = CreateCourse();

        var result = _controller.Details(course.CourseID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(course.CourseID, model.CourseID);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(result.ViewData["DepartmentID"]);
    }

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course { CourseID = 2001, Title = "New Course", Credits = 4, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Courses);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 2001, Credits = 4, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
        Assert.Empty(_context.Courses);
    }

    [Fact]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 2001, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(1024);

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 2001, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_SavesFileAndRedirects()
    {
        var course = new Course { CourseID = 2001, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.png");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = _context.Courses.Find(2001);
        Assert.NotNull(saved);
        Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        var course = CreateCourse();

        var result = _controller.Edit(course.CourseID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(course.CourseID, model.CourseID);
    }

    [Fact]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = CreateCourse();
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        course.Title = "Updated Title";

        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        var course = CreateCourse();
        _controller.ModelState.AddModelError("Title", "Required");

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = CreateCourse();
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.txt");
        fileMock.Setup(f => f.Length).Returns(1024);

        var result = _controller.Edit(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = CreateCourse();
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024);

        var result = _controller.Edit(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        var course = CreateCourse();

        var result = _controller.Delete(course.CourseID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(course.CourseID, model.CourseID);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        var course = CreateCourse();

        var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Courses.Find(course.CourseID));
    }

    #endregion
}

