using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestDbContext.Create();
        _controller = new DepartmentsController(_context);

        // Seed an instructor for FK
        _context.Instructors.Add(new Instructor
        {
            ID = 1,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2020, 1, 1)
        });
        _context.SaveChanges();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Department CreateDepartment(string name = "Computer Science", decimal budget = 350000)
    {
        var dept = new Department
        {
            Name = name,
            Budget = budget,
            StartDate = new DateTime(2020, 9, 1),
            InstructorID = 1
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        CreateDepartment("CS");
        CreateDepartment("Math");

        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(result.ViewData["InstructorID"]);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "Biology",
            Budget = 200000,
            StartDate = new DateTime(2021, 9, 1),
            InstructorID = 1
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { Budget = 200000, StartDate = DateTime.Now };

        var result = _controller.Create(dept) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(result.ViewData["InstructorID"]);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();

        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = CreateDepartment();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        dept.Name = "Updated Dept";

        var result = _controller.Edit(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        var dept = CreateDepartment();
        _controller.ModelState.AddModelError("Name", "Required");

        var result = _controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(result.ViewData["InstructorID"]);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();

