using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContext.Create();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor CreateInstructor(string lastName = "Smith", string firstName = "John")
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Course CreateCourse(int id, string title = "Test Course")
    {
        var dept = _context.Departments.FirstOrDefault();
        if (dept == null)
        {
            dept = new Department { Name = "Test Dept", Budget = 100000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();
        }
        var course = new Course { CourseID = id, Title = title, Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    #region Index

    [Fact]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        CreateInstructor("Alpha", "A");
        CreateInstructor("Beta", "B");

        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        var instructor = CreateInstructor();
        var course = CreateCourse(1001);
        var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        // Re-fetch to reflect navigation properties
        var result = _controller.Index(instructor.ID, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
    }

    [Fact]
    public void Index_WithCourseId_PopulatesEnrollments()
    {
        var instructor = CreateInstructor();
        var course = CreateCourse(1002);
        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });

        var student = new Student { LastName = "Doe", FirstMidName = "J", EnrollmentDate = DateTime.Now };
        _context.Students.Add(student);
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment { CourseID = course.CourseID, StudentID = student.ID, Grade = Grade.A });
        _context.SaveChanges();

        var result = _controller.Index(instructor.ID, course.CourseID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.NotNull(model.Enrollments);
        Assert.Single(model.Enrollments);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        var instructor = CreateInstructor();

        var result = _controller.Details(instructor.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithCourseData()
    {
        CreateCourse(1001, "Course A");

        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(result.ViewData["Courses"]);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "New",
            FirstMidName = "Instructor",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        CreateCourse(1001);
        CreateCourse(1002);
        var instructor = new Instructor
        {
            LastName = "New",
            FirstMidName = "Instructor",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, new[] { "1001", "1002" }) as RedirectToActionResult;

        Assert.NotNull(result);
        var saved = _context.Instructors.First(i => i.LastName == "New");
        // Verify assignments were created
        var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
        Assert.Equal(2, assignments.Count);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        var instructor = CreateInstructor();

        var result = _controller.Delete(instructor.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        var instructor = CreateInstructor();
        // Add OfficeAssignment as Delete loads it
        _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instructor.ID, Location = "Office 1" });
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Instructors.Find(instructor.ID));
    }

    [Fact]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        var instructor = CreateInstructor();
        var dept = new Department
        {
            Name = "Test Dept",
            Budget = 100000,
            StartDate = DateTime.Now,
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _controller.DeleteConfirmed(instructor.ID);

        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.Null(updatedDept!.InstructorID);
    }

    #endregion
}

