using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        _context = TestDbContext.Create();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void GetNotifications_ReturnsJsonWithSuccessTrue()
    {
        var result = _controller.GetNotifications();

        Assert.NotNull(result);
        // JsonResult value contains anonymous object
        var value = result.Value;
        Assert.NotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.NotNull(successProp);
        Assert.True((bool)successProp.GetValue(value)!);
    }

    [Fact]
    public void GetNotifications_ReturnsNotificationsArray()
    {
        // Send a notification first via the base controller's notification service
        // The controller inherits notificationService from BaseController
        // We can trigger via SendEntityNotification indirectly by creating a student
        var studentsController = new StudentsController(_context);
        var student = new Models.Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };
        studentsController.Create(student);
        studentsController.Dispose();

        var result = _controller.GetNotifications();
        var value = result.Value!;
        var countProp = value.GetType().GetProperty("count");
        var count = (int)countProp!.GetValue(value)!;
        Assert.True(count >= 1);
    }

    [Fact]
    public void MarkAsRead_ReturnsJsonWithSuccessTrue()
    {
        var result = _controller.MarkAsRead(1);

        Assert.NotNull(result);
        var value = result.Value!;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(value)!);
    }
}

