using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestDbContext.Create();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.Find(student.ID);

        Assert.NotNull(retrieved);
        Assert.Equal("Test", retrieved.LastName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        var dept = new Department { Name = "CS", Budget = 100000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 3001, Title = "Algorithms", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var retrieved = _context.Courses.Find(3001);

        Assert.NotNull(retrieved);
        Assert.Equal("Algorithms", retrieved.Title);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var instructor = new Instructor
        {
            LastName = "Instructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1)
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var retrieved = _context.Instructors.Find(instructor.ID);

        Assert.NotNull(retrieved);
        Assert.Equal("Instructor", retrieved.LastName);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        var dept = new Department
        {
            Name = "Mathematics",
            Budget = 250000,
            StartDate = new DateTime(2020, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var retrieved = _context.Departments.Find(dept.DepartmentID);

        Assert.NotNull(retrieved);
        Assert.Equal("Mathematics", retrieved.Name);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        var instructor = new Instructor
        {
            LastName = "Prof",
            FirstMidName = "A",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
