using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Data;

public class DbInitializerTests : IDisposable
{
    private readonly SchoolContext _context;

    public DbInitializerTests()
    {
        _context = TestDbContext.Create();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void Initialize_EmptyDatabase_SeedsData()
    {
        DbInitializer.Initialize(_context);

        Assert.Equal(8, _context.Students.Count());
        Assert.Equal(5, _context.Instructors.Count());
        Assert.Equal(4, _context.Departments.Count());
        Assert.Equal(7, _context.Courses.Count());
        Assert.True(_context.Enrollments.Any());
        Assert.True(_context.OfficeAssignments.Any());
        Assert.True(_context.CourseAssignments.Any());
    }

    [Fact]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Seed once
        DbInitializer.Initialize(_context);
        var studentCount = _context.Students.Count();

        // Seed again - should be no-op
        DbInitializer.Initialize(_context);

        Assert.Equal(studentCount, _context.Students.Count());
    }

    [Fact]
    public void Initialize_SetsUpCourseAssignments()
    {
        DbInitializer.Initialize(_context);

        var assignments = _context.CourseAssignments.ToList();
        Assert.Equal(8, assignments.Count);
    }

    [Fact]
    public void Initialize_SetsUpOfficeAssignments()
    {
        DbInitializer.Initialize(_context);

        var offices = _context.OfficeAssignments.ToList();
        Assert.Equal(3, offices.Count);
    }

    [Fact]
    public void Initialize_EnrollmentsHaveGrades()
    {
        DbInitializer.Initialize(_context);

        var enrollmentsWithGrades = _context.Enrollments.Where(e => e.Grade != null).ToList();
        Assert.True(enrollmentsWithGrades.Count > 0);
    }
}

