using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

/// <summary>
/// Additional tests for CoursesController Edit with image upload.
/// </summary>
public class CoursesControllerEditImageTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly string _tempDir;

    public CoursesControllerEditImageTests()
    {
        _context = TestDbContext.Create();
        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);

        var envMock = new Mock<IWebHostEnvironment>();
        envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
        var loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, envMock.Object, loggerMock.Object);

        _context.Departments.Add(new Department { DepartmentID = 1, Name = "Eng", Budget = 100000, StartDate = DateTime.Now });
        _context.SaveChanges();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
            Directory.Delete(_tempDir, true);
    }

    [Fact]
